# Logo real EL TORO embebido para evitar error de carga en Render/GitHub.
TORO_LOGO_B64 = """"""

def ensure_static_logo():
    import base64 as _base64
    os.makedirs(STATIC_DIR, exist_ok=True)
    logo_path = os.path.join(STATIC_DIR, "toro_logo.png")
    if not os.path.exists(logo_path) or os.path.getsize(logo_path) < 1000:
        with open(logo_path, "wb") as f:
            f.write(_base64.b64decode(TORO_LOGO_B64))
    return logo_path

ensure_static_logo()


# =========================
# HELPERS DB
# =========================
def now():
    return datetime.now(APP_TZ)

def today():
    return now().date().isoformat()

def next_work_date(fecha):
    try:
        return (datetime.strptime(fecha, "%Y-%m-%d").date() + timedelta(days=1)).isoformat()
    except Exception:
        return (now().date() + timedelta(days=1)).isoformat()

def hour():
    # Hora oficial de trabajo en Perú, formato 24 horas.
    return now().strftime("%H:%M:%S")

def hour_short():
    return now().strftime("%H:%M")

def now_display():
    return now().strftime("%d/%m/%Y %H:%M:%S")

def money(v):
    try:
        return "S/ {:,.2f}".format(float(v or 0))
    except Exception:
        return "S/ 0.00"

def clean(v):
    return str(v or "").strip()

def up(v):
    return clean(v).upper()

def conn():
    c = sqlite3.connect(DB_PATH)
    c.row_factory = sqlite3.Row
    return c

def q_all(sql, params=()):
    with conn() as c:
        return c.execute(sql, params).fetchall()

def q_one(sql, params=()):
    rows = q_all(sql, params)
    return rows[0] if rows else None

def q_exec(sql, params=()):
    with conn() as c:
        cur = c.execute(sql, params)
        c.commit()
        return cur.lastrowid

def log_event(accion, detalle=""):
    try:
        q_exec(
            "INSERT INTO logs(fecha,hora,usuario,accion,detalle) VALUES(?,?,?,?,?)",
            (today(), hour(), session.get("user", "sistema"), accion, detalle),
        )
    except Exception:
        pass

