def get_ctx(k, default=""):
    r = q_one("SELECT valor FROM contexto WHERE clave=?", (k,))
    return r["valor"] if r else default

def set_ctx(k, v):
    if q_one("SELECT clave FROM contexto WHERE clave=?", (k,)):
        q_exec("UPDATE contexto SET valor=? WHERE clave=?", (str(v), k))
    else:
        q_exec("INSERT INTO contexto(clave,valor) VALUES(?,?)", (k, str(v)))

def sucursal_actual_id():
    try:
        return int(session.get("sucursal_id") or 1)
    except Exception:
        return 1

def sucursal_nombre(sucursal_id=None):
    sid = sucursal_id or sucursal_actual_id()
    r = q_one("SELECT nombre FROM sucursales WHERE id=?", (sid,))
    return r["nombre"] if r else "Sucursal Principal"

def sucursal_abierta(sucursal_id=None):
    """Estado operativo por sucursal. True permite ventas/POS/pedidos/cobros."""
    sid = sucursal_id or sucursal_actual_id()
    r = q_one("SELECT abierta, activo FROM sucursales WHERE id=?", (sid,))
    if not r:
        return str(get_ctx("sucursal_cerrada", "0")).strip() != "1"
    return int(r["activo"] or 0) == 1 and int(r["abierta"] if r["abierta"] is not None else 1) == 1

def estado_sucursal_label(sucursal_id=None):
    return "ABIERTA" if sucursal_abierta(sucursal_id) else "CERRADA"

def bloquear_si_sucursal_cerrada(destino="ventas"):
    if not sucursal_abierta():
        flash(f"{sucursal_nombre()} está CERRADA. Abre la sucursal desde Usuarios/Admin o Cierre para continuar.", "error")
        return redirect(url_for(destino))
    return None

def tabs():
    # Admin trabaja con panel vertical fijo; no necesita panel horizontal.
    if session.get("rol") == "ADMIN":
        return []
    return [
        ("ventas", "Venta", "ventas"),
        ("pos", "POS rápido", "pos_rapido"),
        ("pedidos", "Pedido", "pedidos"),
        ("catalogo", "Catálogo", "catalogo_admin"),
    ]

def page(content, active="dashboard"):
    return render_template_string(
        BASE_HTML,
        content=content,
        active=active,
        title=APP_TITLE,
        subtitle=APP_SUBTITLE,
        brand=BRAND,
        tabs=tabs(),
        money=money,
        now_display=now_display(),
        hour_short=hour_short(),
        current_date=today(),
        current_sucursal="Sucursal Principal",
    )

def select_options(rows, value_key="id", text_key="nombre", selected=None):
    out = []
    for r in rows:
        val = str(r[value_key])
        sel = "selected" if selected is not None and str(selected) == val else ""
        out.append(f'<option value="{val}" {sel}>{r[text_key]}</option>')
    return "".join(out)

# =========================
# LÓGICA NEGOCIO
# =========================
def recetas_activas():
    """True cuando el modo RECETAS está ON.
    En modo prueba queda OFF para vender sin descontar insumos ni bloquear operaciones.
    """
    return str(get_ctx("recetas_activas", "0")).strip() == "1"

def descontar_receta(producto_id, cantidad_producto):
    # MODO PRUEBA SIN RECETAS:
    # Si recetas está OFF, NO descuenta insumos. Esto permite probar ventas, POS, pedidos, caja y delivery
    # sin depender de configuración de recetas/insumos.
    if not recetas_activas():
        return
    for r in q_all("SELECT * FROM recetas WHERE producto_id=?", (producto_id,)):
        q_exec(
            "UPDATE insumos SET stock=COALESCE(stock,0)-? WHERE id=?",
            (float(r["cantidad"] or 0) * float(cantidad_producto or 0), r["insumo_id"]),
        )

def descontar_producto(producto_id, cantidad):
    # El stock del producto sí puede bajar; el descuento de INSUMOS depende de RECETAS OFF/ON.
    q_exec("UPDATE productos SET stock=COALESCE(stock,0)-? WHERE id=?", (float(cantidad or 0), producto_id))
    descontar_receta(producto_id, cantidad)

def clave_cliente_inteligente(nombre, telefono='', direccion=''):
    """Clave robusta: teléfono si existe; si no, nombre + dirección."""
    tel = clean(telefono)
    nom = up(nombre or 'CLIENTE GENERAL')
    dire = up(direccion or '')
    if tel:
        return 'TEL:' + tel
    base = (nom + '|' + dire).strip('|')
    return 'NOMDIR:' + base if base else ''

def separar_nombre_apellido(nombre):
    partes = up(nombre).split()
    if len(partes) <= 1:
        return up(nombre), ''
    return partes[0], ' '.join(partes[1:])

def codigo_cliente_nuevo(cliente_id):
    return f"CLI-{int(cliente_id):06d}"

def asegurar_cliente(nombre, telefono='', direccion='', referencia='', notas='', origen='VENTAS'):
    """Centraliza clientes desde POS, Ventas y Delivery.
    - Teléfono no obligatorio.
    - Si no hay teléfono, detecta por nombre + dirección.
    - A partir de 3 visitas lo marca como frecuente.
    """
    nombre_full = up(nombre or 'CLIENTE GENERAL')
    telefono = clean(telefono)
    direccion = up(direccion)
    referencia = up(referencia)
    notas = up(notas)
    origen = up(origen or 'VENTAS')
    if not nombre_full or nombre_full == 'CLIENTE GENERAL':
        return None
    clave = clave_cliente_inteligente(nombre_full, telefono, direccion)
    nom, ape = separar_nombre_apellido(nombre_full)
    r = None
    if telefono:
        r = q_one("SELECT * FROM clientes WHERE activo=1 AND telefono<>'' AND telefono=? LIMIT 1", (telefono,))
    if not r and clave:
        r = q_one("SELECT * FROM clientes WHERE activo=1 AND clave_cliente=? LIMIT 1", (clave,))
    if not r and direccion:
        r = q_one("SELECT * FROM clientes WHERE activo=1 AND UPPER(nombre)=UPPER(?) AND UPPER(direccion)=UPPER(?) LIMIT 1", (nombre_full, direccion))
    if not r:
        r = q_one("SELECT * FROM clientes WHERE activo=1 AND UPPER(nombre)=UPPER(?) AND (telefono='' OR telefono IS NULL) LIMIT 1", (nombre_full,))
    if r:
        visitas = int(r['visitas'] or 0) + 1 if 'visitas' in r.keys() else 1
        frecuente = 1 if visitas >= 3 else 0
        q_exec("""
            UPDATE clientes
               SET nombre=COALESCE(NULLIF(?,''),nombre),
                   apellido=COALESCE(NULLIF(?,''),apellido),
                   telefono=COALESCE(NULLIF(?,''),telefono),
                   direccion=COALESCE(NULLIF(?,''),direccion),
                   referencia=COALESCE(NULLIF(?,''),referencia),
                   notas=COALESCE(NULLIF(?,''),notas),
                   visitas=?, es_frecuente=?, origen_ultimo=?, ultima_visita=?, clave_cliente=COALESCE(NULLIF(?,''),clave_cliente)
             WHERE id=?
        """, (nombre_full, ape, telefono, direccion, referencia, notas, visitas, frecuente, origen, today()+' '+hour(), clave, r['id']))
        return r['id']
    new_id = q_exec("""
        INSERT INTO clientes(nombre,apellido,telefono,direccion,referencia,notas,activo,visitas,es_frecuente,origen_ultimo,ultima_visita,clave_cliente)
        VALUES(?,?,?,?,?,?,1,1,0,?,?,?)
    """, (nombre_full, ape, telefono, direccion, referencia, notas, origen, today()+' '+hour(), clave))
    q_exec("UPDATE clientes SET codigo_cliente=? WHERE id=?", (codigo_cliente_nuevo(new_id), new_id))
    return new_id

def cliente_to_dict(r):
    return {
        'id': r['id'],
        'codigo_cliente': r['codigo_cliente'] if 'codigo_cliente' in r.keys() else f"CLI-{int(r['id']):06d}",
        'nombre': r['nombre'] or '',
        'apellido': r['apellido'] if 'apellido' in r.keys() else '',
        'telefono': r['telefono'] or '',
        'direccion': r['direccion'] or '',
        'referencia': r['referencia'] or '',
        'notas': r['notas'] or '',
        'visitas': int(r['visitas'] or 0) if 'visitas' in r.keys() else 0,
        'es_frecuente': int(r['es_frecuente'] or 0) if 'es_frecuente' in r.keys() else 0,
        'origen_ultimo': r['origen_ultimo'] if 'origen_ultimo' in r.keys() else '',
    }

def agregar_item_a_pedido(pedido_id, producto_id, cantidad=1):
    prod = q_one("SELECT * FROM productos WHERE id=? AND activo=1", (producto_id,))
    if not prod:
        return False, 'Producto no válido.'
    cantidad = int(float(cantidad or 1))
    precio = float(prod['precio'] or 0)
    subtotal = precio * cantidad
    q_exec("INSERT INTO pedido_detalle(pedido_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)", (pedido_id, producto_id, prod['nombre'], cantidad, precio, subtotal))
    descontar_producto(producto_id, cantidad)
    total_items = q_one("SELECT COALESCE(SUM(total),0) t FROM pedido_detalle WHERE pedido_id=?", (pedido_id,))['t']
    desc = q_one("SELECT COALESCE(descuento,0) d FROM pedidos WHERE id=?", (pedido_id,))['d']
    q_exec("UPDATE pedidos SET subtotal=?, total=max(?-?,0), estado=CASE WHEN estado='PAGADO' THEN 'PENDIENTE' ELSE estado END, pagado=CASE WHEN pagado='SI' THEN 'NO' ELSE pagado END WHERE id=?", (total_items, total_items, desc, pedido_id))
    return True, 'Ítem agregado al pedido inicial.'

def crear_venta_desde_pedido(pedido_id, metodo_pago="EFECTIVO"):
    if not sucursal_abierta():
        return None
    p = q_one("SELECT * FROM pedidos WHERE id=?", (pedido_id,))
    if not p:
        return None
    if p["pagado"] == "SI":
        return None
    if p["estado"] != "ENTREGADO":
        return None
    vid = q_exec(
        "INSERT INTO ventas(fecha,hora,pedido_id,cliente,servicio,metodo_pago,subtotal,descuento,total,usuario,estado,sucursal_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)",
        (today(), hour(), pedido_id, p["cliente"], p["servicio"], metodo_pago, p["subtotal"], p["descuento"], p["total"], session.get("user", ""), "PAGADO", session.get("sucursal_id",1)),
    )
    for d in q_all("SELECT * FROM pedido_detalle WHERE pedido_id=?", (pedido_id,)):
        q_exec(
            "INSERT INTO venta_detalle(venta_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)",
            (vid, d["producto_id"], d["producto"], d["cantidad"], d["precio"], d["total"]),
        )
        # Stock ya se descuenta al crear/agregar el pedido; no duplicar descuento al cobrar.
    q_exec("UPDATE pedidos SET pagado='SI', estado='PAGADO' WHERE id=?", (pedido_id,))
    q_exec(
        "INSERT INTO caja(fecha,hora,tipo,concepto,monto,usuario,venta_id,sucursal_id) VALUES(?,?,?,?,?,?,?,?)",
        (today(), hour(), "INGRESO", f"VENTA PEDIDO {p['codigo']}", p["total"], session.get("user", ""), vid, session.get("sucursal_id",1)),
    )
    log_event("VENTA", f"Pedido cobrado {p['codigo']}")
    return vid

