@app.route("/ventas", methods=["GET", "POST"])
@login_required
def ventas():
    if request.method == "POST":
        accion = request.form.get("accion", "guardar_pedido")
        if accion != "importar_productos" and not sucursal_abierta():
            flash("Sucursal Principal está CERRADA. No se pueden registrar ventas, pedidos ni cobros.", "error")
            return redirect(url_for("ventas"))
        if accion != "importar_productos" and get_ctx("caja_abierta", "0") != "1":
            flash("Primero debes ABRIR CAJA para registrar ventas, pedidos o cobros.", "error")
            return redirect(url_for("caja"))
        if accion == "importar_productos" and "archivo" in request.files:
            if not is_admin():
                flash("Carga de inicio de día restringida: solo administrador.", "error")
                return redirect(url_for("ventas"))
            count = importar_productos(request.files["archivo"])
            flash(f"Carga inicio día completada: {count} productos actualizados.", "ok")
            return redirect(url_for("ventas"))
        producto_id = int(request.form.get("producto_id") or 0)
        cantidad = int(float(request.form.get("cantidad") or 1))
        if accion in ("guardar_pedido", "pos_rapido", "agregar_a_pedido"):
            prod = q_one("SELECT * FROM productos WHERE id=? AND activo=1", (producto_id,))
            if not prod:
                flash("Selecciona un producto válido.", "error")
                return redirect(url_for("ventas"))
            pedido_existente = int(request.form.get("pedido_existente_id") or 0)
            if accion == "agregar_a_pedido" or pedido_existente:
                if not pedido_existente:
                    flash("Selecciona el pedido inicial para agregar el producto.", "error")
                    return redirect(url_for("ventas"))
                ok, msg = agregar_item_a_pedido(pedido_existente, producto_id, cantidad)
                flash(msg, "ok" if ok else "error")
                return redirect(url_for("pedidos"))
            descuento = float(request.form.get("descuento") or 0)
            precio = float(prod["precio"] or 0)
            subtotal = precio * cantidad
            total = max(subtotal - descuento, 0)
            codigo = "PED-" + now().strftime("%Y%m%d-%H%M%S")
            cliente = up(request.form.get("cliente") or "CLIENTE GENERAL")
            telefono = clean(request.form.get("telefono"))
            direccion = up(request.form.get("direccion"))
            referencia = up(request.form.get("referencia"))
            asegurar_cliente(cliente, telefono, direccion, referencia, origen='VENTAS')
            pedido_id = q_exec("INSERT INTO pedidos(codigo,fecha,hora,mesa,cliente,telefono,direccion,referencia,servicio,metodo_pago,subtotal,descuento,total,estado,pagado,usuario,observacion,sucursal_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)", (codigo, today(), hour(), request.form.get("mesa", ""), cliente, telefono, direccion, referencia, request.form.get("servicio", "SALÓN"), request.form.get("metodo_pago", "EFECTIVO"), subtotal, descuento, total, "PENDIENTE", "NO", session.get("user"), "", session.get("sucursal_id",1)))
            q_exec("INSERT INTO pedido_detalle(pedido_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)", (pedido_id, producto_id, prod["nombre"], cantidad, precio, total))
            descontar_producto(producto_id, cantidad)
            log_event("PEDIDO", f"Creado {codigo} - {prod['nombre']}")
            flash(f"Pedido guardado: {prod['nombre']} x {cantidad}.", "ok")
            return redirect(url_for("pos_rapido") if accion == "pos_rapido" else url_for("ventas"))
        if accion == "cobrar_boleta":
            pedido_id = int(request.form.get("pedido_id") or 0)
            metodo = request.form.get("metodo_pago", "EFECTIVO")
            vid = crear_venta_desde_pedido(pedido_id, metodo)
            if vid and metodo in ("YAPE", "PLIN", "TRANSFERENCIA"):
                return redirect(url_for("pago_qr", pedido_id=pedido_id, metodo=metodo))
            flash("Pedido cobrado y boleta generada." if vid else "No se pudo cobrar: verifica que el pedido exista y no esté pagado.", "ok" if vid else "error")
            return redirect(url_for("ventas"))
    buscar_prod = clean(request.args.get("buscar", ""))
    solo_disp = request.args.get("disponible", "") == "1"
    cat_filtro = clean(request.args.get("categoria", ""))
    where = ["activo=1"]
    params = []
    if buscar_prod:
        like = f"%{buscar_prod.upper()}%"
        where.append("(UPPER(nombre) LIKE ? OR UPPER(categoria) LIKE ? OR UPPER(codigo) LIKE ?)")
        params += [like, like, like]
    if solo_disp:
        where.append("COALESCE(stock,0)>0")
    if cat_filtro:
        where.append("UPPER(categoria)=UPPER(?)")
        params.append(cat_filtro)
    productos = q_all("SELECT * FROM productos WHERE " + " AND ".join(where) + " ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre", tuple(params))
    # Fallback PRO: si el filtro deja el combo vacío, mostrar todos los productos activos para no bloquear la venta.
    if not productos:
        productos = q_all("SELECT * FROM productos WHERE activo=1 ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre LIMIT 250")
        if not productos:
            init_db()
            productos = q_all("SELECT * FROM productos WHERE activo=1 ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre LIMIT 250")
    categorias = q_all("SELECT DISTINCT categoria FROM productos WHERE activo=1 AND COALESCE(categoria,'')<>'' ORDER BY categoria")
    opts_prod = '<option value="" data-cat="">Selecciona producto</option>' + "".join(f'<option value="{p["id"]}" data-cat="{str(p["categoria"] or "").upper()}">{p["codigo"] or p["id"]} · {p["nombre"]} · {money(p["precio"])} · Stock {int(float(p["stock"] or 0))}</option>' for p in productos)
    tr_prod = "".join(f'<tr class="{"row-ok" if float(r["stock"] or 0)>0 else "row-bad"}"><td>{r["codigo"]}</td><td><b>{r["nombre"]}</b></td><td>{r["categoria"]}</td><td>{money(r["precio"])}</td><td>{int(float(r["stock"] or 0))}</td><td>{"DISPONIBLE" if float(r["stock"] or 0)>0 else "SIN STOCK"}</td></tr>' for r in productos[:150]) or '<tr><td colspan="6">Sin productos.</td></tr>'
    pedidos_pend = q_all("SELECT p.*, COALESCE((SELECT GROUP_CONCAT(producto || ' x' || CAST(cantidad AS INT), ' + ') FROM pedido_detalle d WHERE d.pedido_id=p.id),'') productos FROM pedidos p WHERE p.pagado='NO' ORDER BY p.id DESC LIMIT 80")
    opts_ped = '<option value="">Selecciona pedido abierto</option>' + "".join(f'<option value="{p["id"]}">{p["codigo"]} · {p["cliente"]} · {p["productos"]} · {money(p["total"])} · {p["estado"]}</option>' for p in pedidos_pend)
    cat_opts = '<option value="">Todas las categorías</option>' + ''.join(f'<option value="{c["categoria"]}" {"selected" if cat_filtro==c["categoria"] else ""}>{c["categoria"]}</option>' for c in categorias)
    cat_venta_opts = '<option value="">Todas las categorías</option>' + ''.join(f'<option value="{c["categoria"]}">{c["categoria"]}</option>' for c in categorias)
    cat_links = '<div class="category-bar"><a class="' + ('' if cat_filtro else 'on') + '" href="' + url_for('ventas') + '#catalogo-productos">TODOS</a>' + ''.join(f'<a class="{"on" if cat_filtro==c["categoria"] else ""}" href="{url_for("ventas", categoria=c["categoria"], disponible="1" if solo_disp else "")}#catalogo-productos">{c["categoria"]}</a>' for c in categorias) + '</div>'
    clientes = q_all("SELECT * FROM clientes WHERE activo=1 ORDER BY es_frecuente DESC, visitas DESC, nombre LIMIT 300")
    cliente_options = "".join(f'<option value="{c["nombre"]}">⭐ {c["visitas"] if "visitas" in c.keys() else 0} · {c["telefono"] or "SIN CEL"} · {c["direccion"]}</option>' for c in clientes)
    detalle = q_all("SELECT d.*,p.codigo FROM pedido_detalle d JOIN pedidos p ON p.id=d.pedido_id ORDER BY d.id DESC LIMIT 40")
    tr_det = "".join(f'<tr><td>{r["codigo"]}</td><td><b>{r["producto"]}</b></td><td>{int(float(r["cantidad"] or 0))}</td><td>{money(r["precio"])}</td><td>{money(r["total"])}</td></tr>' for r in detalle) or '<tr><td colspan="5">Sin detalle.</td></tr>'
    pos_cards = ""
    for p in productos[:24]:
        img_row = q_one("SELECT imagen FROM catalogo_publico WHERE UPPER(titulo)=UPPER(?) AND activo=1 ORDER BY destacado DESC,id DESC LIMIT 1", (p['nombre'],))
        img_html = f"<img src='{url_for('static', filename=img_row['imagen'])}' alt='{p['nombre']}'>" if img_row and img_row['imagen'] else ""
        pos_cards += f"""<form method='post' class='pos-card-form'><input type='hidden' name='accion' value='pos_rapido'><input type='hidden' name='producto_id' value='{p['id']}'><input type='hidden' name='cantidad' value='1'><input type='hidden' name='cliente' value='CLIENTE GENERAL'><input type='hidden' name='servicio' value='SALÓN'><input type='hidden' name='metodo_pago' value='EFECTIVO'><button class='pos-product' type='submit'>{img_html}<b>{p['nombre']}</b><span>{money(p['precio'])}</span><small>SKU {p['codigo'] or p['id']} · Stock {int(float(p['stock'] or 0))}</small></button></form>"""
    load_day_html = ""
    if is_admin():
        load_day_html = f"""<div class='panel load-day-panel'><div class='section-title'>📥 Carga de inicio de día</div><div class='hint-card'>Solo ADMIN: importa Excel/CSV para actualizar productos, precios y stock antes de iniciar ventas.</div><br><form method='post' enctype='multipart/form-data' class='actions'><input type='hidden' name='accion' value='importar_productos'><input type='file' name='archivo' accept='.xlsx,.csv' style='max-width:420px'><button class='btn-warning'>📥 Cargar día / importar Excel productos</button><a class='btn' href='{url_for('plantilla_inventario')}'>📄 Descargar plantilla</a></form></div>"""
    estado_operativo_html = ""
    if not sucursal_abierta():
        estado_operativo_html += "<div class='flash error'>🔒 Sucursal Principal CERRADA: abre la sucursal desde Usuarios/Admin para iniciar pruebas.</div>"
    if get_ctx("caja_abierta", "0") != "1":
        estado_operativo_html += f"<div class='flash error'>💵 Caja SIN ABRIR: abre caja antes de vender. <a class='btn-warning' href='{url_for('caja')}'>Abrir caja</a></div>"
    else:
        estado_operativo_html += "<div class='flash ok'>💵 Caja ABIERTA: ventas y pedidos habilitados.</div>"
    html = f"""
    {estado_operativo_html}
    <div class='panel'><div class='section-title'>➕ Agregar producto a pedido inicial</div><div class='hint-card'>Busca el pedido abierto del cliente y agrega gaseosa, pollo, pizza u otro producto. El importe sube en el mismo pedido y el detalle queda disgregado por ítem.</div><form method='post' class='clean-grid'><input type='hidden' name='accion' value='agregar_a_pedido'><div><label>Pedido inicial / cliente</label><select name='pedido_existente_id' required>{opts_ped}</select></div><div><label>Categoría</label><select class='venta-cat-filter' data-target='producto_add'>{cat_venta_opts}</select></div><div><label>Producto a agregar</label><select id='producto_add' name='producto_id' class='venta-product-select' required>{opts_prod}</select></div><div><label>Cantidad</label><input name='cantidad' type='number' min='1' step='1' value='1'></div><button class='btn-success'>Agregar al mismo pedido</button></form></div>
    <div class='panel'><div class='section-title'>🧾 Nueva venta / pedido</div><br><form method='post'><input type='hidden' name='accion' value='guardar_pedido'><datalist id='clientes_list'>{cliente_options}</datalist><div class='clean-grid-4'><div><label>Mesa</label><select name='mesa'><option></option><option>MESA 1</option><option>MESA 2</option><option>MESA 3</option><option>MESA 4</option><option>MESA 5</option><option>MESA 6</option></select></div><div><label>Tipo servicio</label><select name='servicio'><option>SALÓN</option><option>DELIVERY</option><option>RECOJO</option></select></div><div><label>Cliente</label><input name='cliente' list='clientes_list' placeholder='Buscar o escribir cliente'></div><div><label>Teléfono</label><input name='telefono' placeholder='Celular'></div><div><label>Dirección</label><input name='direccion' placeholder='Solo para delivery'></div><div><label>Referencia</label><input name='referencia' placeholder='Referencia'></div><div><label>Categoría</label><select class='venta-cat-filter' data-target='producto_new' name='categoria_venta'>{cat_venta_opts}</select></div><div><label>Producto</label><select id='producto_new' name='producto_id' class='venta-product-select' required>{opts_prod}</select></div><div><label>Cantidad</label><input name='cantidad' type='number' min='1' step='1' value='1'></div><div><label>Descuento</label><input name='descuento' type='number' min='0' step='1' value='0'></div></div><br><div class='actions'><button class='primary'>Guardar pedido</button><a class='btn' href='{url_for('pedidos')}'>Ver pedidos</a></div></form></div>
    <div id="crm_alerta" class="hint-card" style="display:none;margin-top:12px;background:#fff7ed;border-color:#fed7aa;color:#9a3412;font-weight:900"></div>
    <script>
      async function buscarClienteCRM(term){{
        term=(term||'').trim();
        if(term.length<3) return null;
        try{{
          const r=await fetch('/api/clientes/buscar?term='+encodeURIComponent(term));
          const data=await r.json();
          return data.ok ? data.cliente : null;
        }}catch(e){{return null;}}
      }}
      async function autocompletarVentaDesde(input){{
        const c=await buscarClienteCRM(input.value);
        const alerta=document.getElementById('crm_alerta');
        if(!c){{ if(alerta) alerta.style.display='none'; return; }}
        const form=input.closest('form')||document;
        const cliente=form.querySelector('[name="cliente"]');
        const telefono=form.querySelector('[name="telefono"]');
        const direccion=form.querySelector('[name="direccion"]');
        const referencia=form.querySelector('[name="referencia"]');
        if(cliente && !cliente.value) cliente.value=c.nombre;
        if(telefono && !telefono.value) telefono.value=c.telefono;
        if(direccion && !direccion.value) direccion.value=c.direccion;
        if(referencia && !referencia.value) referencia.value=c.referencia;
        if(alerta){{
          alerta.style.display='block';
          alerta.innerHTML=(c.es_frecuente?'⭐ Cliente frecuente detectado: ':'Cliente detectado: ')+c.nombre+' · visitas: '+c.visitas+' · '+(c.telefono||'sin celular');
        }}
      }}
      document.querySelectorAll('[name="cliente"],[name="telefono"]').forEach(el=>{{
        el.addEventListener('change',()=>autocompletarVentaDesde(el));
        el.addEventListener('blur',()=>autocompletarVentaDesde(el));
      }});
    </script>
    <div class='panel'><div class='box-title'>Cobro rápido</div><br><form method='post' class='actions'><input type='hidden' name='accion' value='cobrar_boleta'><select name='pedido_id' style='max-width:680px'>{opts_ped}</select><select name='metodo_pago' style='max-width:220px'><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option><option>TRANSFERENCIA</option></select><button class='btn-success'>Cobrar y boleta / QR</button></form></div>
    <div class='panel filter-sticky' id='filtros-venta'><form method='get' action='{url_for('ventas')}#catalogo-productos' class='catalog-filter-actions'><div><label>Buscar producto</label><input name='buscar' value='{buscar_prod}' placeholder='Buscar producto por nombre, código o categoría'></div><div><label>Categoría</label><select name='categoria' onchange='this.form.submit()'>{cat_opts}</select></div><button name='disponible' value='1'>✅ Filtrar disponibles</button><a class='btn' href='{url_for('ventas')}#catalogo-productos'>Limpiar</a></form></div>
    <div class='panel' id='catalogo-productos'><div class='section-title'>🍽️ Catálogo de productos <span class="title-count-pill">{len(productos)} productos</span></div><div class="catalog-mini-kpi"><b>{len(productos)}</b><span>productos visibles según filtro</span></div><div class='table-wrap small'><table><thead><tr><th>Código</th><th>Producto</th><th>Categoría</th><th>Precio</th><th>Stock</th><th>Estado</th></tr></thead><tbody>{tr_prod}</tbody></table></div></div>{load_day_html}
    <div class='panel'><div class='section-title'>🧩 Últimos ítems registrados</div><div class='table-wrap small'><table><thead><tr><th>Pedido</th><th>Producto</th><th>Cantidad</th><th>Precio</th><th>Subtotal</th></tr></thead><tbody>{tr_det}</tbody></table></div></div>
    <script>
    document.querySelectorAll('.venta-cat-filter').forEach(function(sel){{
      const target=document.getElementById(sel.dataset.target);
      if(!target) return;
      const original=[...target.options].map(o=>({{value:o.value,text:o.text,cat:(o.dataset.cat||'').toUpperCase()}}));
      function filtrar(){{
        const cat=(sel.value||'').toUpperCase();
        target.innerHTML='';
        original.forEach(function(o,i){{
          if(i===0 || !cat || o.cat===cat){{
            const opt=document.createElement('option');
            opt.value=o.value; opt.text=o.text; opt.dataset.cat=o.cat; target.appendChild(opt);
          }}
        }});
        target.selectedIndex=0;
      }}
      sel.addEventListener('change',filtrar);
      filtrar();
    }});
    </script>"""
    return page(html, "ventas")


@app.route("/pos_rapido", methods=["GET", "POST"])
@login_required
def pos_rapido():
    if request.method == "POST":
        if not sucursal_abierta():
            flash("Sucursal Principal está CERRADA. No se puede usar POS rápido.", "error")
            return redirect(url_for("pos_rapido"))
        if get_ctx("caja_abierta", "0") != "1":
            flash("Primero debes ABRIR CAJA para registrar pedidos desde POS rápido.", "error")
            return redirect(url_for("caja"))
        producto_id = int(request.form.get("producto_id") or 0)
        cantidad = int(float(request.form.get("cantidad") or 1))
        prod = q_one("SELECT * FROM productos WHERE id=? AND activo=1", (producto_id,))
        if not prod:
            flash("Selecciona un producto válido.", "error")
            return redirect(url_for("pos_rapido"))
        descuento = float(request.form.get("descuento") or 0)
        precio = float(prod["precio"] or 0)
        subtotal = precio * cantidad
        total = max(subtotal - descuento, 0)
        codigo = "PED-" + now().strftime("%Y%m%d-%H%M%S")
        cliente = up(request.form.get("cliente") or "CLIENTE GENERAL")
        telefono = clean(request.form.get("telefono"))
        direccion = up(request.form.get("direccion"))
        referencia = up(request.form.get("referencia"))
        servicio = request.form.get("servicio", "SALÓN")
        metodo = request.form.get("metodo_pago", "EFECTIVO")
        asegurar_cliente(cliente, telefono, direccion, referencia, origen='POS')
        pedido_unico = 1 if request.form.get('pedido_unico') else 0
        if pedido_unico:
            existente = q_one("""
SELECT * FROM pedidos
 WHERE pagado='NO' AND estado NOT IN ('PAGADO','ENTREGADO')
   AND UPPER(COALESCE(cliente,''))=UPPER(?)
   AND COALESCE(telefono,'')=COALESCE(?, '')
   AND COALESCE(mesa,'')=COALESCE(?, '')
   AND COALESCE(servicio,'')=COALESCE(?, '')
 ORDER BY id DESC LIMIT 1""", (cliente, telefono, request.form.get("mesa", ""), servicio))
            if existente:
                ok, msg = agregar_item_a_pedido(existente['id'], producto_id, cantidad)
                flash(('Pedido único actualizado: ' + prod['nombre']) if ok else msg, 'ok' if ok else 'error')
                return redirect(url_for('pos_rapido'))
        pedido_id = q_exec("INSERT INTO pedidos(codigo,fecha,hora,mesa,cliente,telefono,direccion,referencia,servicio,metodo_pago,subtotal,descuento,total,estado,pagado,usuario,observacion,sucursal_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)", (codigo, today(), hour(), request.form.get("mesa", ""), cliente, telefono, direccion, referencia, servicio, metodo, subtotal, descuento, total, "PENDIENTE", "NO", session.get("user"), "POS RÁPIDO APP MÓVIL", session.get("sucursal_id",1)))
        q_exec("INSERT INTO pedido_detalle(pedido_id,producto_id,producto,cantidad,precio,total) VALUES(?,?,?,?,?,?)", (pedido_id, producto_id, prod["nombre"], cantidad, precio, total))
        descontar_producto(producto_id, cantidad)
        log_event("POS", f"POS rápido móvil {codigo} - {cliente} - {prod['nombre']}")
        flash(f"POS guardado: {cliente} · {prod['nombre']} x {cantidad}.", "ok")
        return redirect(url_for("pos_rapido"))

    buscar_prod = clean(request.args.get("buscar", ""))
    cat_filtro = clean(request.args.get("categoria", ""))
    where = ["activo=1"]
    params = []
    if buscar_prod:
        like = f"%{buscar_prod.upper()}%"
        where.append("(UPPER(nombre) LIKE ? OR UPPER(categoria) LIKE ? OR UPPER(codigo) LIKE ?)")
        params += [like, like, like]
    if cat_filtro:
        where.append("UPPER(categoria)=UPPER(?)")
        params.append(cat_filtro)
    productos = q_all("SELECT * FROM productos WHERE " + " AND ".join(where) + " ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre", tuple(params))
    # Fallback PRO: si el filtro deja el combo vacío, mostrar todos los productos activos para no bloquear la venta.
    if not productos:
        productos = q_all("SELECT * FROM productos WHERE activo=1 ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre LIMIT 250")
        if not productos:
            init_db()
            productos = q_all("SELECT * FROM productos WHERE activo=1 ORDER BY categoria, CASE WHEN stock>0 THEN 0 ELSE 1 END, nombre LIMIT 250")
    categorias = q_all("SELECT DISTINCT categoria FROM productos WHERE activo=1 AND COALESCE(categoria,'')<>'' ORDER BY categoria")
    clientes = q_all("SELECT * FROM clientes WHERE activo=1 ORDER BY es_frecuente DESC, visitas DESC, nombre LIMIT 300")
    cliente_options = "".join(f'<option value="{c["nombre"]}">⭐ {c["visitas"] if "visitas" in c.keys() else 0} · {c["telefono"] or "SIN CEL"} · {c["direccion"]}</option>' for c in clientes)
    cat_opts = '<option value="">Todas las categorías</option>' + ''.join(f'<option value="{c["categoria"]}" {"selected" if cat_filtro==c["categoria"] else ""}>{c["categoria"]}</option>' for c in categorias)
    cat_links = '<div class="pos-cat-chips"><a class="' + ('' if cat_filtro else 'on') + '" href="' + url_for('pos_rapido') + '">TODOS</a>' + ''.join(f'<a class="{"on" if cat_filtro==c["categoria"] else ""}" href="{url_for("pos_rapido", categoria=c["categoria"])}">{c["categoria"]}</a>' for c in categorias) + '</div>'

    def product_image(prod):
        img_row = q_one("SELECT imagen FROM catalogo_publico WHERE UPPER(titulo)=UPPER(?) AND activo=1 ORDER BY destacado DESC,id DESC LIMIT 1", (prod['nombre'],))
        return url_for('static', filename=(img_row['imagen'] if img_row and img_row['imagen'] else 'toro_logo.png'))

    feature_cards = ""
    for p in productos[:6]:
        img = product_image(p)
        feature_cards += f"""<form method='post' class='keep-pos-form' onclick='event.stopPropagation()'>
          <input type='hidden' name='producto_id' value='{p['id']}'><input type='hidden' name='cantidad' value='1'>
          <input type='hidden' name='cliente' class='pos_cliente_hidden' value='CLIENTE GENERAL'><input type='hidden' name='telefono' class='pos_telefono_hidden' value=''><input type='hidden' name='direccion' class='pos_direccion_hidden' value=''><input type='hidden' name='referencia' class='pos_referencia_hidden' value=''>
          <input type='hidden' name='mesa' class='pos_mesa_hidden' value=''><input type='hidden' name='servicio' class='pos_servicio_hidden' value='SALÓN'><input type='hidden' name='pedido_unico' class='pos_unico_hidden' value=''>
          <button class='pos-feature-card' type='submit'><img src='{img}' alt='{p['nombre']}'><b>{p['nombre']}</b><span>{money(p['precio'])}</span><em class='pos-mini-add'>Agregar</em></button>
        </form>"""

    list_cards = ""
    for p in productos[:90]:
        img = product_image(p)
        list_cards += f"""<form method='post' class='keep-pos-form pos-list-item'>
          <input type='hidden' name='producto_id' value='{p['id']}'><input type='hidden' name='cantidad' value='1'>
          <input type='hidden' name='cliente' class='pos_cliente_hidden' value='CLIENTE GENERAL'><input type='hidden' name='telefono' class='pos_telefono_hidden' value=''><input type='hidden' name='direccion' class='pos_direccion_hidden' value=''><input type='hidden' name='referencia' class='pos_referencia_hidden' value=''>
          <input type='hidden' name='mesa' class='pos_mesa_hidden' value=''><input type='hidden' name='servicio' class='pos_servicio_hidden' value='SALÓN'><input type='hidden' name='pedido_unico' class='pos_unico_hidden' value=''>
          <img class='pos-list-img' src='{img}' alt='{p['nombre']}'>
          <div class='pos-list-info'><b>{p['nombre']}</b><small>{p['categoria'] or 'PRODUCTO'} · SKU {p['codigo'] or p['id']} · Stock {int(float(p['stock'] or 0))}</small><span>{money(p['precio'])}</span></div>
          <button class='pos-list-add' type='submit'>Agregar</button>
        </form>"""
    if not list_cards:
        list_cards = "<div class='pos-empty'>No hay productos para la búsqueda.</div>"
    if not feature_cards:
        feature_cards = "<div class='pos-empty'>Carga productos para iniciar ventas rápidas.</div>"

    estado_caja_pos = ""
    if get_ctx("caja_abierta", "0") != "1":
        estado_caja_pos = f"<div class='flash error'>💵 Caja SIN ABRIR: primero abre caja. <a class='btn-warning' href='{url_for('caja')}'>Abrir caja</a></div>"
    else:
        estado_caja_pos = "<div class='flash ok'>💵 Caja ABIERTA: POS rápido habilitado.</div>"
    html = f"""
    {estado_caja_pos}
    <div class="panel pos-client-panel">
      <div class="section-title">⚡ POS rápido móvil</div>
      <div class="hint-card">Identifica cliente, mesa y servicio. Marca pedido único para agregar varios productos al mismo pedido. El pago se define en Pedidos.</div><br>
      <datalist id="clientes_pos_list">{cliente_options}</datalist>
      <form method="get" class="pos-client-grid">
        <div><label>Cliente</label><input id="pos_cliente" list="clientes_pos_list" placeholder="CLIENTE GENERAL / nombre"></div>
        <div><label>Teléfono / DNI</label><input id="pos_telefono" placeholder="Celular o DNI"></div>
        <div><label>Dirección</label><input id="pos_direccion" placeholder="Para delivery"></div>
        <div><label>Referencia</label><input id="pos_referencia" placeholder="Portón, piso, nota"></div>
        <div><label>Mesa</label><select id="pos_mesa"><option></option><option>MESA 1</option><option>MESA 2</option><option>MESA 3</option><option>MESA 4</option><option>MESA 5</option><option>MESA 6</option></select></div>
        <div><label>Servicio</label><select id="pos_servicio"><option>SALÓN</option><option>RECOJO</option><option>DELIVERY</option></select></div>
        <label class="pos-unico-check"><input type="checkbox" id="pos_unico" style="width:auto"> Generar un solo pedido con varios ítems</label>
      </form>
    </div>
    <div class="pos-mobile-shell">
      <section class="pos-phone">
        <div class="pos-phone-top"><span>←</span><span>☰</span></div>
        <div class="pos-hero-card"><h2>El sabor<br>que te provoca</h2></div>
        <div class="pos-category-title">Categoría de comida</div>
        <div class="pos-feature-grid">{feature_cards}</div>
        <div class="pos-category-title">Categoría de comida</div>
        <div class="pos-feature-grid">{feature_cards}</div>
      </section>
      <section class="pos-list-phone">
        <form method="get" action="{url_for('pos_rapido')}" class="pos-search-row">
          <input name="buscar" value="{buscar_prod}" placeholder="Buscar producto">
          <select name="categoria" onchange="this.form.submit()">{cat_opts}</select>
          <button type="submit">🔎</button><a class="pos-gear" href="{url_for('pos_rapido')}">⚙️</a>
        </form>
        {cat_links}
        <div class="pos-list-stack">{list_cards}</div>
      </section>
    </div>
    <script>
      function syncPOSClient(){{
        const cliente=(document.getElementById('pos_cliente').value||'CLIENTE GENERAL').trim() || 'CLIENTE GENERAL';
        const telefono=(document.getElementById('pos_telefono').value||'').trim();
        const direccion=(document.getElementById('pos_direccion')?.value||'').trim();
        const referencia=(document.getElementById('pos_referencia')?.value||'').trim();
        const mesa=document.getElementById('pos_mesa').value||'';
        const servicio=document.getElementById('pos_servicio').value||'SALÓN';
        const unico=document.getElementById('pos_unico')?.checked ? '1' : '';
        document.querySelectorAll('.pos_cliente_hidden').forEach(e=>e.value=cliente);
        document.querySelectorAll('.pos_telefono_hidden').forEach(e=>e.value=telefono);
        document.querySelectorAll('.pos_mesa_hidden').forEach(e=>e.value=mesa);
        document.querySelectorAll('.pos_servicio_hidden').forEach(e=>e.value=servicio);
        document.querySelectorAll('.pos_unico_hidden').forEach(e=>e.value=unico);
        try{{sessionStorage.setItem('pos_cliente',cliente);sessionStorage.setItem('pos_telefono',telefono);sessionStorage.setItem('pos_mesa',mesa);sessionStorage.setItem('pos_servicio',servicio);sessionStorage.setItem('pos_unico',unico);}}catch(e){{}}
      }}
      ['pos_cliente','pos_telefono','pos_mesa','pos_servicio','pos_unico'].forEach(id=>{{const el=document.getElementById(id); if(el) el.addEventListener('input',syncPOSClient); if(el) el.addEventListener('change',syncPOSClient);}});
      window.addEventListener('load',function(){{try{{document.getElementById('pos_cliente').value=sessionStorage.getItem('pos_cliente')||'';document.getElementById('pos_telefono').value=sessionStorage.getItem('pos_telefono')||'';document.getElementById('pos_mesa').value=sessionStorage.getItem('pos_mesa')||'';document.getElementById('pos_servicio').value=sessionStorage.getItem('pos_servicio')||'SALÓN';document.getElementById('pos_unico').checked=(sessionStorage.getItem('pos_unico')==='1');}}catch(e){{}} syncPOSClient();}});
      document.querySelectorAll('.keep-pos-form').forEach(f=>f.addEventListener('submit',syncPOSClient));
    </script>
    """
    return page(html, "pos")

@app.route("/pedidos", methods=["GET", "POST"])
@login_required
def pedidos():
    if request.method == "POST":
        accion = request.form.get("accion")
        pedido_id = int(request.form.get("pedido_id") or 0)
        if not pedido_id:
            flash("Selecciona un pedido.", "error")
            return redirect(url_for("pedidos"))
        pedido_actual = q_one("SELECT estado,pagado FROM pedidos WHERE id=?", (pedido_id,))
        if accion == "estado":
            if pedido_actual and (pedido_actual["estado"] in ("ENTREGADO", "PAGADO") or pedido_actual["pagado"] == "SI"):
                flash("Este pedido ya fue entregado o pagado; no se puede cambiar desde el desplegable.", "error")
                return redirect(url_for("pedidos"))
            nuevo = request.form.get("estado", "PENDIENTE")
            if nuevo == "PAGADO":
                flash("Para pagar usa el botón Marcar pagado; así se registra caja y venta.", "error")
            else:
                q_exec("UPDATE pedidos SET estado=? WHERE id=?", (nuevo, pedido_id))
                flash("Estado actualizado.", "ok")
        elif accion == "pagado":
            if pedido_actual and (pedido_actual["pagado"] == "SI" or pedido_actual["estado"] == "PAGADO"):
                flash("Este pedido ya está pagado; no aparece en el cobro pendiente.", "error")
                return redirect(url_for("pedidos"))
            vid = crear_venta_desde_pedido(pedido_id, request.form.get("metodo_pago", "EFECTIVO"))
            flash("Pedido marcado como pagado." if vid else "Primero cambia el estado del pedido a ENTREGADO para poder cobrar.", "ok" if vid else "error")
        elif accion == "quitar_item":
            if pedido_actual and (pedido_actual["estado"] in ("ENTREGADO", "PAGADO") or pedido_actual["pagado"] == "SI"):
                flash("No se puede quitar ítems de un pedido entregado o pagado.", "error")
                return redirect(url_for("pedidos"))
            item_id = int(request.form.get("item_id") or 0)
            if item_id:
                q_exec("DELETE FROM pedido_detalle WHERE id=? AND pedido_id=?", (item_id, pedido_id))
                total = q_one("SELECT COALESCE(SUM(total),0) t FROM pedido_detalle WHERE pedido_id=?", (pedido_id,))["t"]
                q_exec("UPDATE pedidos SET subtotal=?, total=max(?-COALESCE(descuento,0),0) WHERE id=?", (total, total, pedido_id))
                flash("Item retirado del pedido.", "ok")
        elif accion == "limpiar":
            q_exec("DELETE FROM pedido_detalle WHERE pedido_id=?", (pedido_id,))
            q_exec("DELETE FROM pedidos WHERE id=?", (pedido_id,))
            flash("Pedido eliminado.", "ok")
        return redirect(url_for("pedidos"))

    estado = request.args.get("estado", "TODOS")
    sucid = session.get("sucursal_id", 1)
    base_sql = "SELECT p.*, COALESCE((SELECT GROUP_CONCAT(producto || ' x' || CAST(cantidad AS INT), ' + ') FROM pedido_detalle d WHERE d.pedido_id=p.id),'') productos FROM pedidos p"
    if is_admin():
        rows = q_all(base_sql + " ORDER BY p.id DESC LIMIT 200") if estado == "TODOS" else q_all(base_sql + " WHERE p.estado=? ORDER BY p.id DESC LIMIT 200", (estado,))
    else:
        rows = q_all(base_sql + " WHERE COALESCE(p.sucursal_id,1)=? ORDER BY p.id DESC LIMIT 200", (sucid,)) if estado == "TODOS" else q_all(base_sql + " WHERE COALESCE(p.sucursal_id,1)=? AND p.estado=? ORDER BY p.id DESC LIMIT 200", (sucid, estado))
    # Listas separadas para evitar operaciones incorrectas:
    # - Estado: solo pedidos NO entregados y NO pagados.
    # - Cobro: solo pedidos abiertos/no pagados.
    # - Quitar ítem: solo pedidos editables, no entregados ni pagados.
    pedidos_estado = [r for r in rows if (r["estado"] not in ("ENTREGADO", "PAGADO") and r["pagado"] != "SI")]
    pedidos_cobro = [r for r in rows if (r["pagado"] != "SI" and r["estado"] == "ENTREGADO")]
    pedidos_editables_ids = {r["id"] for r in pedidos_estado}

    def pedido_label(r):
        cliente = r["cliente"] or "CLIENTE GENERAL"
        productos = r["productos"] or "Sin ítems"
        return f'{cliente} · {r["codigo"]} · {productos} · {r["estado"]} · {money(r["total"])}'

    opts_estado = '<option value="">Selecciona pedido pendiente por cliente o código</option>' + "".join(
        f'<option value="{r["id"]}">{pedido_label(r)}</option>' for r in pedidos_estado
    )
    opts_cobro = '<option value="">Selecciona pedido abierto por cliente o código</option>' + "".join(
        f'<option value="{r["id"]}">{pedido_label(r)}</option>' for r in pedidos_cobro
    )
    selected_first = (pedidos_cobro[0]["id"] if pedidos_cobro else (pedidos_estado[0]["id"] if pedidos_estado else 0))
    detalles = q_all("SELECT d.*,p.codigo,p.cliente,p.estado,p.pagado FROM pedido_detalle d JOIN pedidos p ON p.id=d.pedido_id ORDER BY d.id DESC LIMIT 120")
    detalles_editables = [r for r in detalles if r["pedido_id"] in pedidos_editables_ids]
    item_opts = '<option value="">Selecciona ítem editable</option>' + "".join(
        f'<option value="{r["id"]}">#{r["id"]} · {r["cliente"] or "CLIENTE GENERAL"} · {r["codigo"]} · {r["producto"]} · Cant. {int(float(r["cantidad"] or 0))}</option>' for r in detalles_editables
    )
    tr_items = "".join(
        f'<tr><td>{r["id"]}</td><td>{r["codigo"]}</td><td><b>{r["producto"]}</b></td><td>{int(float(r["cantidad"] or 0))}</td><td>{money(r["precio"])}</td><td>{money(r["total"])}</td></tr>'
        for r in detalles
    ) or '<tr><td colspan="6">Sin detalle de ítems.</td></tr>'
    total_abierto = sum(float(r["total"] or 0) for r in rows if r["pagado"] == "NO")
    pendientes = sum(1 for r in rows if r["estado"] not in ("PAGADO","ENTREGADO"))
    resumen_cards = f"<div class='pedido-resumen'><div class='pedido-card'><b>{len(rows)}</b><br>Pedidos encontrados</div><div class='pedido-card'><b>{pendientes}</b><br>Pendientes de cocina</div><div class='pedido-card'><b>{money(total_abierto)}</b><br>Importe abierto</div></div>"
    trs = "".join(f'<tr><td>{r["id"]}</td><td>{r["codigo"]}</td><td>{r["fecha"]}</td><td>{r["hora"]}</td><td>{r["mesa"]}</td><td>{r["cliente"]}</td><td><b class="pedido-prod-text">{r["productos"] or "Sin ítems"}</b></td><td>{r["servicio"]}</td><td><span class="badge warn">{r["estado"]}</span></td><td>{money(r["total"])}</td><td>{r["pagado"]}</td></tr>' for r in rows) or '<tr><td colspan="11">Sin pedidos.</td></tr>'
    pedido_bloques = ""
    for r in rows[:24]:
        editable = (r["estado"] not in ("ENTREGADO", "PAGADO") and r["pagado"] != "SI")
        if editable:
            action_html = f'''<form method="post" class="pedido-bloque-actions"><input type="hidden" name="pedido_id" value="{r['id']}"><select name="estado"><option>PREPARACIÓN</option><option>LISTO</option><option>ENTREGADO</option></select><button name="accion" value="estado" class="btn-success">Actualizar</button><select name="metodo_pago"><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option></select><button name="accion" value="pagado" class="btn-success" onclick="return confirm('Solo se cobra si el pedido está ENTREGADO')">Cobrar</button><a class="btn-warning full" href="{url_for('boleta', pedido_id=r['id'])}">Imprimir boleta</a></form>''' 
        else:
            action_html = f'''<div class="pedido-bloque-actions"><a class="btn-warning full" href="{url_for('boleta', pedido_id=r['id'])}">Imprimir boleta</a></div>''' 
        pedido_bloques += f'''<div class="pedido-bloque"><div class="pedido-bloque-head"><div><h3>{r['cliente'] or 'CLIENTE GENERAL'}</h3><span class="pedido-code">{r['codigo']}</span></div><span class="badge warn">{r['estado']}</span></div><div class="pedido-products">{r['productos'] or 'Sin ítems'}</div><div class="pedido-meta"><span>Hora: {r['fecha']} {r['hora']}</span><span>Mesa/servicio: {r['mesa'] or r['servicio']}</span><span>Pagado: {r['pagado']}</span><span>Usuario: {r['usuario'] or ''}</span></div><div class="pedido-total">{money(r['total'])}</div>{action_html}</div>''' 
    if not pedido_bloques:
        pedido_bloques = '<div class="hint-card">Sin pedidos para mostrar.</div>' 
    chips = "".join(f'<div class="item-chip"><b>{r["producto"]}</b><span>{r["codigo"]} · {r["cliente"]}</span><br>Cant. {int(float(r["cantidad"] or 0))} · {money(r["precio"])} · <b>{money(r["total"])}</b></div>' for r in detalles) or '<div class="hint-card">Sin detalle de ítems.</div>'
    html = f'''
    <div class="mobile-active-title">🚚 Pedidos</div>
    <div class="panel"><div class="section-title">🚚 Control de pedidos / cocina</div>{resumen_cards}
      <form method="get" class="clean-grid"><div><label>Filtrar por estado</label><select name="estado"><option>TODOS</option><option>PENDIENTE</option><option>PREPARACIÓN</option><option>LISTO</option><option>ENTREGADO</option></select></div><button>Refrescar</button><a class="btn" href="{url_for('ventas')}">Nuevo pedido</a></form><br>
      <div class="section-title">📦 Pedidos en bloques</div><div class="pedido-bloques">{pedido_bloques}</div><br>
      <div class="pedido-operaciones-grid">
        <form method="post" class="pedido-op-card smart-pedido-form"><div class="pedido-op-title">🔁 Cambiar estado</div><div><label>Pedido pendiente / cliente</label><input class="pedido-search" placeholder="Buscar por nombre, código o producto"><select name="pedido_id" class="pedido-select">{opts_estado}</select><small class="muted">No muestra entregados ni pagados.</small></div><div><label>Cambiar a estado</label><select name="estado"><option>PREPARACIÓN</option><option>LISTO</option><option>ENTREGADO</option></select></div><button name="accion" value="estado" class="btn-success">Actualizar estado</button></form>
        <form method="post" class="pedido-op-card smart-pedido-form"><div class="pedido-op-title">💵 Cobrar pedido</div><div><label>Pedido para cobrar</label><input class="pedido-search" placeholder="Buscar por nombre, código o producto"><select name="pedido_id" class="pedido-select">{opts_cobro}</select><small class="muted">Solo pedidos ENTREGADOS y no pagados.</small></div><div><label>Método pago</label><select name="metodo_pago"><option>EFECTIVO</option><option>YAPE</option><option>PLIN</option><option>TARJETA</option></select></div><div class="actions"><button name="accion" value="pagado" class="btn-success">Marcar pagado</button><button name="accion" value="limpiar" class="btn-danger" onclick="return confirm('¿Eliminar pedido completo?')">Eliminar pedido</button><a class="btn" href="{url_for('boleta', pedido_id=selected_first)}">Imprimir boleta</a></div></form>
        <form method="post" class="pedido-op-card smart-pedido-form"><div class="pedido-op-title">✏️ Editar ítems</div><div><label>Pedido editable</label><input class="pedido-search" placeholder="Buscar por nombre, código o producto"><select name="pedido_id" class="pedido-select">{opts_estado}</select><small class="muted">No muestra entregados ni pagados.</small></div><div><label>Ítem del pedido</label><select name="item_id">{item_opts}</select></div><button name="accion" value="quitar_item" class="btn-warning">➖ Quitar ítem</button></form>
      </div>
      <script>
      document.querySelectorAll('.smart-pedido-form').forEach(function(form){{
        const input=form.querySelector('.pedido-search');
        const select=form.querySelector('.pedido-select');
        if(!input||!select) return;
        const original=[...select.options].map(o=>({{value:o.value,text:o.text}}));
        input.addEventListener('input',function(){{
          const q=input.value.toLowerCase().trim();
          const current=select.value;
          select.innerHTML='';
          original.forEach(function(o,i){{
            if(i===0 || !q || o.text.toLowerCase().includes(q)){{
              const opt=document.createElement('option'); opt.value=o.value; opt.text=o.text; select.appendChild(opt);
            }}
          }});
          if([...select.options].some(o=>o.value===current)) select.value=current;
          else if(select.options.length>1) select.selectedIndex=1;
        }});
      }});
      </script>
    </div>
    <div class="panel"><div class="section-title">📋 Listado de pedidos</div><div class="table-wrap"><table><thead><tr><th>ID</th><th>Código</th><th>Fecha</th><th>Hora</th><th>Mesa</th><th>Cliente</th><th>Productos</th><th>Servicio</th><th>Estado</th><th>Total</th><th>Pagado</th></tr></thead><tbody>{trs}</tbody></table></div></div>
    <div class="panel"><div class="section-title">🧾 Detalle de ítems</div><div class="table-wrap detalle-table-simple"><table><thead><tr><th>Pedido ID</th><th>Código</th><th>Producto</th><th>Cantidad</th><th>Precio</th><th>Subtotal</th></tr></thead><tbody>{tr_items}</tbody></table></div></div>'''
    return page(html, "pedidos")

@app.route("/boleta/<int:pedido_id>")
@login_required
def boleta(pedido_id):
    p = q_one("SELECT * FROM pedidos WHERE id=?", (pedido_id,)) if pedido_id else q_one("SELECT * FROM pedidos ORDER BY id DESC LIMIT 1")
    if not p:
        return "Sin pedido"
    det = q_all("SELECT * FROM pedido_detalle WHERE pedido_id=?", (p["id"],))
    lines = ["EL TORO RESTAURANT GRILL", "BOLETA", f"Pedido: {p['codigo']}", f"Fecha: {p['fecha']} {p['hora']}", f"Cliente: {p['cliente']}", "-" * 32]
    for d in det:
        lines.append(f"{d['cantidad']} x {d['producto']} {money(d['total'])}")
    lines += ["-" * 32, f"TOTAL: {money(p['total'])}"]
    bio = BytesIO("\n".join(lines).encode("utf-8"))
    return send_file(bio, as_attachment=True, download_name=f"boleta_{p['codigo']}.txt", mimetype="text/plain")


