@app.route('/api/live/resumen')
@login_required
def api_live_resumen():
    """Resumen ligero para refresco en vivo desde web/app."""
    f = today()
    sucid = session.get('sucursal_id', 1)
    where_suc = " AND COALESCE(sucursal_id,1)=?" if not is_admin() else ""
    params = (f, sucid) if not is_admin() else (f,)
    try:
        pedidos_dia = q_one("SELECT COUNT(*) c FROM pedidos WHERE fecha=?" + where_suc, params)['c']
        pendientes = q_one("SELECT COUNT(*) c FROM pedidos WHERE fecha=? AND estado NOT IN ('PAGADO','ENTREGADO')" + where_suc, params)['c']
        ventas = q_one("SELECT COALESCE(SUM(total),0) t FROM pedidos WHERE fecha=? AND pagado='SI'" + where_suc, params)['t']
        return jsonify({'ok': True, 'fecha': f, 'pedidos': pedidos_dia, 'pendientes': pendientes, 'ventas': float(ventas or 0)})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500

@app.route('/api/live/pedidos')
@login_required
def api_live_pedidos():
    """Pedidos en vivo. Admin ve todo; vendedor ve su sucursal."""
    sucid = session.get('sucursal_id', 1)
    if is_admin():
        rows = q_all("SELECT id,codigo,fecha,hora,cliente,servicio,estado,total,pagado FROM pedidos ORDER BY id DESC LIMIT 50")
    else:
        rows = q_all("SELECT id,codigo,fecha,hora,cliente,servicio,estado,total,pagado FROM pedidos WHERE COALESCE(sucursal_id,1)=? ORDER BY id DESC LIMIT 50", (sucid,))
    return jsonify({'ok': True, 'pedidos': [dict(r) for r in rows]})


@app.route('/api/productos/categoria')
@login_required
def api_productos_categoria():
    cat = clean(request.args.get('categoria'))
    params = []
    where = "WHERE activo=1"
    if cat and cat.upper() not in ('TODAS', 'TODOS', 'TODAS LAS CATEGORÍAS', 'TODAS LAS CATEGORIAS'):
        where += " AND UPPER(categoria)=UPPER(?)"
        params.append(cat)
    rows = q_all(f"SELECT id,codigo,nombre,categoria,precio,stock FROM productos {where} ORDER BY categoria,nombre", tuple(params))
    return jsonify({'ok': True, 'productos': [dict(r) for r in rows]})

@app.route("/logs")
@login_required
@admin_required
def logs():
    rows = q_all("SELECT * FROM logs ORDER BY id DESC LIMIT 300")
    trs = "".join(f'<tr><td>{r["fecha"]}</td><td>{r["hora"]}</td><td>{r["usuario"]}</td><td>{r["accion"]}</td><td>{r["detalle"]}</td></tr>' for r in rows) or '<tr><td colspan="5">Sin log.</td></tr>'
    return page(f'<div class="panel"><div class="box-title">Log del sistema</div><br><div class="table-wrap"><table><thead><tr><th>Fecha</th><th>Hora</th><th>Usuario</th><th>Acción</th><th>Detalle</th></tr></thead><tbody>{trs}</tbody></table></div></div>', "log")

@app.errorhandler(500)
def err500(e):
    try:
        log_event("ERROR 500", str(e))
    except Exception:
        pass
    return page('<div class="panel"><h2>Error interno controlado</h2><p>No se perdió información. Revisa los logs de Render o vuelve al panel.</p><a class="btn btn-primary" href="/dashboard">Volver al panel</a></div>'), 500


